<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> suite</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> new</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Benchmark.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Suite</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span>
